package main

import (
    "crypto/rand"
    "crypto/sha256"
    "encoding/hex"
    "fmt"
    "golang.org/x/crypto/bcrypt"
)

// Compliant: Using bcrypt (recommended)
func hashPasswordSecure(password string) (string, error) {
    // bcrypt automatically generates random salt
    hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
    return string(hash), err
}

func verifyPassword(password, hash string) bool {
    err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password))
    return err == nil
}

// Compliant: Manual implementation with cryptographic random salt
func hashPasswordManual(password string) (string, string, error) {
    // Generate cryptographically secure random salt
    salt := make([]byte, 32)
    _, err := rand.Read(salt)
    if err != nil {
        return "", "", err
    }

    // Combine password and salt
    combined := append([]byte(password), salt...)
    hash := sha256.Sum256(combined)

    return hex.EncodeToString(hash[:]), hex.EncodeToString(salt), nil
}
